package chain

import (
	"math/big"
	"testing"

	"github.com/ethereum/go-ethereum/accounts/abi"
	"github.com/ethereum/go-ethereum/common"
	"github.com/ethereum/go-ethereum/core/types"
)

func TestHasIgnoredSwapToken(t *testing.T) {
	log := &types.Log{
		Data: common.FromHex(""),
	}

	ignored, err := hasIgnoredSwapToken(log, true)
	if err != nil {
		t.Fatalf("hasIgnoredSwapToken failed: %v", err)
	}
	if !ignored {
		t.Fatal("expected ignored swap token")
	}
}

func TestDecodeMessageRelayTokensIgnoresUnsupportedSwapData(t *testing.T) {
	innerArgs := abi.Arguments{
		{Type: mustType("bytes32")},
		{Type: mustType("address")},
		{Type: mustType("address")},
		{Type: mustType("uint256")},
		{Type: mustType("address")},
		{Type: mustType("bytes")},
		{Type: mustType("bytes")},
	}
	payload, err := innerArgs.Pack(
		[32]byte{3},
		common.HexToAddress("0x0000317Bec33Af037b5fAb2028f52d14658F6A56"),
		common.HexToAddress("0x7046933234A82AF77F14625e8d0fA9Bcc5044a7E"),
		big.NewInt(1),
		common.HexToAddress("0x386ce1a187ec7329cfb8e467eb02fb07c698256a"),
		common.FromHex("0x386ce1a187ec7329cfb8e467eb02fb07c698256a"),
		common.FromHex("0x02"),
	)
	if err != nil {
		t.Fatalf("pack relay payload failed: %v", err)
	}
	outerArgs := abi.Arguments{{Type: mustType("bytes")}}
	data, err := outerArgs.Pack(payload)
	if err != nil {
		t.Fatalf("pack relay log data failed: %v", err)
	}
	log := &types.Log{
		Data: data,
	}

	tokens, err := DecodeMessageRelayTokens(log)
	if err != nil {
		t.Fatalf("DecodeMessageRelayTokens failed: %v", err)
	}
	if tokens.Token != common.HexToAddress("0x7046933234A82AF77F14625e8d0fA9Bcc5044a7E") {
		t.Fatalf("unexpected source token: %s", tokens.Token.Hex())
	}
	if len(tokens.DstToken) != 0 {
		t.Fatalf("expected dst token to be skipped, got 0x%x", tokens.DstToken)
	}
}

func TestDecodeMessageRelayTokensNonEVMPayload(t *testing.T) {
	log := &types.Log{
		Data: common.FromHex(""),
	}

	tokens, err := DecodeMessageRelayTokens(log)
	if err != nil {
		t.Fatalf("DecodeMessageRelayTokens failed: %v", err)
	}
	if tokens.Token != (common.Address{}) {
		t.Fatalf("expected non-EVM 32-byte token to be ignored, got %s", tokens.Token.Hex())
	}
}

func TestHasIgnoredSwapTokenMessageOut(t *testing.T) {
	tests := []struct {
		name string
		data string
	}{
		{
			name: "bsc",
			data: "",
		},
		{
			name: "eth",
			data: "",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			log := &types.Log{Data: common.FromHex(tt.data)}
			ignored, err := hasIgnoredSwapToken(log, false)
			if err != nil {
				t.Fatalf("hasIgnoredSwapToken failed: %v", err)
			}
			if !ignored {
				t.Fatal("expected ignored swap token")
			}
		})
	}
}

func TestDecodeMessageOutTokensDoesNotUseMosAsToken(t *testing.T) {
	log := &types.Log{
		Data: common.FromHex(""),
	}

	tokens, err := DecodeMessageOutTokens(log)
	if err != nil {
		t.Fatalf("DecodeMessageOutTokens failed: %v", err)
	}
	mos := common.HexToAddress("0x0000317Bec33Af037b5fAb2028f52d14658F6A56")
	if tokens.Token == mos {
		t.Fatalf("mos address was parsed as token: %s", tokens.Token.Hex())
	}
	if tokens.Token != common.HexToAddress("0x7046933234A82AF77F14625e8d0fA9Bcc5044a7E") {
		t.Fatalf("unexpected token: %s", tokens.Token.Hex())
	}
}

func TestIgnoredSwapTokenNoMatch(t *testing.T) {
	log := &types.Log{
		Data: common.FromHex(""),
	}

	ignored, err := hasIgnoredSwapToken(log, true)
	if err != nil {
		t.Fatalf("hasIgnoredSwapToken failed: %v", err)
	}
	if ignored {
		t.Fatal("expected non-special token to be unmatched")
	}
}

func TestDecodeMessageOutTokensIgnoresUnsupportedSwapData(t *testing.T) {
	log := &types.Log{
		Data: common.FromHex(""),
	}

	tokens, err := DecodeMessageOutTokens(log)
	if err != nil {
		t.Fatalf("DecodeMessageOutTokens failed: %v", err)
	}
	if tokens.Token != common.HexToAddress("0x0000000000000000000000000000000000000123") {
		t.Fatalf("unexpected source token: %s", tokens.Token.Hex())
	}
	if len(tokens.DstToken) != 0 {
		t.Fatalf("expected dst token to be skipped, got 0x%x", tokens.DstToken)
	}
}
